+// Resize changes the terminal size.
+func (ts *TerminalSession) Resize(cols, rows int) error {
+	ts.mu.Lock()
+	defer ts.mu.Unlock()
+
+	if ts.session == nil {
+		return fmt.Errorf("session not connected")
+	}
+
+	return ts.session.WindowChange(rows, cols)
+}

